        el.style.overflowY = 'auto';
        el.style.overflowX = 'hidden';
        el.scrollTop = el.scrollHeight; // keep cursor visible at bottom
    } else {
        el.style.overflowY = 'hidden';
        el.style.overflowX = 'hidden';
